41	  moonstone: 250,
42	};
43	
44	const DEDUCTIBLE = 100;
45	const CAP_MULTIPLIER = 2;
46	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
47	const HIGH_ENCHANTMENT_CLAIM_RATE = 0.5;
48	
49	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
50	const BLOCK_SIZE = 3;
51	const BLOCK_BASE_PREMIUM = 60;
52	
53	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
54	
55	const countBy = <T>(items: T[], keyOf: (item: T) => string): Record<string, number> => {
56	  const counts: Record<string, number> = {};
57	  for (const item of items) {
58	    const key = keyOf(item);
59	    counts[key] = (counts[key] ?? 0) + 1;
60	  }
61	  return counts;
62	};
63	
64	const countItemsByType = (items: Item[]): Record<string, number> =>
65	  countBy(items, (item) => item.type);
66	
67	const componentGroupPremium = (type: string, count: number): number =>
68	  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * BASE_PREMIUMS[type];
69	
70	const itemsBasePremium = (items: Item[]): number => {
71	  const mainItems = items.filter((item) => !isComponent(item));
72	  const components = items.filter(isComponent);
73	  const mainTotal = mainItems.reduce(
74	    (sum, item) => sum + BASE_PREMIUMS[item.type],
75	    0,
76	  );
77	  const componentTotal = Object.entries(countItemsByType(components)).reduce(
78	    (sum, [type, count]) => sum + componentGroupPremium(type, count),
79	    0,
80	  );
81	  return mainTotal + componentTotal;
82	};
83	
84	const CURSE_SURCHARGE_RATE = 0.5;
85	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
86	const HIGH_ENCHANTMENT_THRESHOLD = 5;
87	
88	const itemModifiersSurcharge = (item: Item): number => {
89	  const base = BASE_PREMIUMS[item.type];
90	  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
91	  const highEnchantment = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
92	  return curse + highEnchantment;
93	};
94	
95	const sumItemModifiers = (items: Item[]): number =>
96	  items.reduce((sum, item) => sum + itemModifiersSurcharge(item), 0);
97	
98	const LOYALTY_DISCOUNT_RATE = 0.2;
99	const LOYALTY_YEARS_THRESHOLD = 2;
100	const FOLLOWUP_CONTRACT_DISCOUNT_RATE = 0.15;
101	
102	const policyLevelAdjustments = (basePremium: number, yearsWithMHPCO: number, isFollowupContract: boolean): number => {
103	  const firstContract = basePremium * FIRST_CONTRACT_SURCHARGE_RATE;
104	  const loyalty = yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? -basePremium * LOYALTY_DISCOUNT_RATE : 0;
105	  const followup = isFollowupContract ? -basePremium * FOLLOWUP_CONTRACT_DISCOUNT_RATE : 0;
106	  return firstContract + loyalty + followup;
107	};
108	
109	const assertKnownItemTypes = (items: Item[]): void => {
110	  for (const item of items) {
111	    if (!(item.type in BASE_PREMIUMS)) throw new Error(`unknown item type: ${item.type}`);
112	  }
113	};
114	
115	const quoteStep = (step: QuoteStep, yearsWithMHPCO: number, isFollowupContract: boolean): QuoteResult => {
116	  assertKnownItemTypes(step.items);
117	  const basePremium = itemsBasePremium(step.items);
118	  const itemModifiers = sumItemModifiers(step.items);
119	  const policyAdjustments = policyLevelAdjustments(basePremium, yearsWithMHPCO, isFollowupContract);
120	  const premium = basePremium + itemModifiers + policyAdjustments + PROCESSING_FEE;
121	  return { premium: Math.ceil(premium) };
122	};
123	
124	type PolicyState = { items: Item[]; insuranceSum: number; remainingCap: number };
125	
126	const insuranceSum = (items: Item[]): number =>
127	  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
128	
129	const isHighEnchantment = (item: Item | undefined): boolean =>
130	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
131	
132	const reimbursableAmount = (item: Item | undefined, amount: number): number =>
133	  isHighEnchantment(item) ? amount * HIGH_ENCHANTMENT_CLAIM_RATE : amount;
134	
135	const damagePayout = (damage: Damage, items: Item[]): number => {
136	  const item = items.find((i) => i.type === damage.itemType);
137	  return reimbursableAmount(item, damage.amount) - DEDUCTIBLE;
138	};
139	
140	const assertNonNegativeAmounts = (damages: Damage[]): void => {
141	  for (const dmg of damages) {
142	    if (dmg.amount < 0) throw new Error(`claim rejected: negative damage amount ${dmg.amount}`);
143	  }
144	};
145	
146	const validateDamageCounts = (damages: Damage[], items: Item[]): void => {
147	  const itemCounts = countItemsByType(items);
148	  const damageCounts = countBy(damages, (dmg) => dmg.itemType);
149	  for (const [type, count] of Object.entries(damageCounts)) {
150	    if (count > (itemCounts[type] ?? 0)) throw new Error(`claim rejected: more damages of type ${type} than insured`);
151	  }
152	};
153	
154	const totalDamagePayout = (damages: Damage[], items: Item[]): number =>
155	  damages.reduce((sum, dmg) => sum + damagePayout(dmg, items), 0);
156	
157	const claimStep = (step: ClaimStep, policies: Map<number, PolicyState>): ClaimResult => {
158	  const policy = policies.get(step.policy)!;
159	  assertNonNegativeAmounts(step.incident.damages);
160	  validateDamageCounts(step.incident.damages, policy.items);
161	  const desiredPayout = totalDamagePayout(step.incident.damages, policy.items);
162	  const payout = Math.floor(Math.min(desiredPayout, policy.remainingCap));
163	  policy.remainingCap -= payout;
164	  return { payout, remainingCap: policy.remainingCap };
165	};
166	
167	const newPolicyState = (items: Item[]): PolicyState => {
168	  const sum = insuranceSum(items);
169	  return { items, insuranceSum: sum, remainingCap: sum * CAP_MULTIPLIER };
170	};
171	
172	export const runScenario = (scenario: Scenario): ScenarioResult => {
173	  const policies = new Map<number, PolicyState>();
174	  const results: StepResult[] = [];
175	  let hasPriorQuote = false;
176	  scenario.steps.forEach((step, idx) => {
177	    if (step.op === "quote") {
178	      results.push(quoteStep(step, scenario.customer.yearsWithMHPCO, hasPriorQuote));
179	      policies.set(idx, newPolicyState(step.items));
180	      hasPriorQuote = true;
181	    } else {
182	      results.push(claimStep(step, policies));
183	    }
184	  });
185	  return { results };
186	};
